#include<cstdio>
#include<cstring>
#include<algorithm>
#define rep(a,b,c) for(register int c=(a);c<=(b);++c)
//#define min(a,b) ((a)<(b)?(a):(b))
//#define max(a,b) ((a)>(b)?(a):(b))
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template<typename T> inline T max(const T&x,const T&y){return x<y?y:x;}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
const int N=1e5+10,Mod=1e9+7;
int a[N][15],n,m,top,len;char s[N],stk[N];
inline int Rd()
{
	char ch;do ch=getchar();while(ch!='('&&(ch<'0'||ch>'9'));
	int p=0;while(ch!='\n'&&ch!='\r')
	{
		switch(ch)
		{
			case ')':while(stk[top]!='(')s[++p]=stk[top--];--top;break;
			case '<':case'>':case '?': if(top&&stk[top]!='(')s[++p]=stk[top--];stk[++top]=ch;break;
			case '(':stk[++top]='(';break;default: s[++p]=ch;break;
		}
		ch=getchar();
	}
	while(top)s[++p]=stk[top--];return p;
}
struct Node{int l,r;char opt;}t[N];int res[1024],dp[N][3],SS;
inline void DP(const int &u)
{
	memset(dp[u],0,sizeof(dp[u]));
	if(!t[u].l){dp[u][!(SS&(1<<(t[u].opt^48)))]=1;return;}
	if(t[u].opt!='>')
	{
		dp[u][0]=(1ll*dp[t[u].l][0]*dp[t[u].r][0]+dp[u][0])%Mod;
		dp[u][0]=(1ll*dp[t[u].l][0]*dp[t[u].r][1]+dp[u][0])%Mod;
		dp[u][0]=(1ll*dp[t[u].l][0]*dp[t[u].r][2]+dp[u][0])%Mod;
		dp[u][0]=(1ll*dp[t[u].l][1]*dp[t[u].r][0]+dp[u][0])%Mod;
		dp[u][1]=(1ll*dp[t[u].l][1]*dp[t[u].r][1]+dp[u][1])%Mod;
		dp[u][1]=(1ll*dp[t[u].l][1]*dp[t[u].r][2]+dp[u][1])%Mod;
		dp[u][0]=(1ll*dp[t[u].l][2]*dp[t[u].r][0]+dp[u][0])%Mod;
		dp[u][0]=(1ll*dp[t[u].l][2]*dp[t[u].r][1]+dp[u][0])%Mod;
		dp[u][2]=(1ll*dp[t[u].l][2]*dp[t[u].r][2]+dp[u][2])%Mod;
	}
	if(t[u].opt!='<')
	{
		dp[u][0]=(1ll*dp[t[u].l][0]*dp[t[u].r][0]+dp[u][0])%Mod;
		dp[u][1]=(1ll*dp[t[u].l][0]*dp[t[u].r][1]+dp[u][1])%Mod;
		dp[u][2]=(1ll*dp[t[u].l][0]*dp[t[u].r][2]+dp[u][2])%Mod;
		dp[u][1]=(1ll*dp[t[u].l][1]*dp[t[u].r][0]+dp[u][1])%Mod;
		dp[u][1]=(1ll*dp[t[u].l][1]*dp[t[u].r][1]+dp[u][1])%Mod;
		dp[u][2]=(1ll*dp[t[u].l][1]*dp[t[u].r][2]+dp[u][2])%Mod;
		dp[u][2]=(1ll*dp[t[u].l][2]*dp[t[u].r][0]+dp[u][2])%Mod;
		dp[u][2]=(1ll*dp[t[u].l][2]*dp[t[u].r][1]+dp[u][2])%Mod;
		dp[u][2]=(1ll*dp[t[u].l][2]*dp[t[u].r][2]+dp[u][2])%Mod;
	}
}
int I;inline bool cmp(const int &x,const int &y){return a[I][x]<a[I][y];}
namespace build
{
	int stk[N],top;inline void mian()
	{
		rep(1,len,j)
		{
			t[j].opt=s[j];if(s[j]<='9'&&s[j]>='0')stk[++top]=j;
			else{--top;t[j].l=stk[top];t[j].r=stk[top+1];stk[top]=j;}
		}
	}
}
int main()
{
//	FIN("expr18.in");
	n=read();m=read();for(int i=0;i<m;++i)rep(1,n,j)a[j][i]=read();len=Rd();build::mian();
	for(SS=0;SS<(1<<m);++SS){rep(1,len,i)DP(i);res[SS]=dp[len][1];}
	int ans=0;for(I=1;I<=n;++I)
	{
		int P[10];for(int i=0;i<m;++i)P[i]=i;std::sort(P,P+m,cmp);ans=(1ll*res[0]*a[I][P[0]]+ans)%Mod;
		int S(1<<P[0]);for(register int i=1;i<m;++i){ans=(1ll*res[S]*(a[I][P[i]]-a[I][P[i-1]])+ans)%Mod;S|=(1<<P[i]);}
	}
	printf("%d\n",ans);return 0;
}
